## 4. Password Reset Flow

```typescript
// app/api/auth/reset-password/route.ts
import { NextResponse } from "next/server";
import crypto from "crypto";
import bcrypt from "bcryptjs";
import { prisma } from "@/lib/prisma";
import { sendEmail } from "@/lib/email";

export async function POST(req: Request) {
  const { email } = await req.json();
  const user = await prisma.user.findUnique({ where: { email } });

  // Always return success to prevent email enumeration
  if (!user) {
    return NextResponse.json({ message: "If account exists, email sent" });
  }

  const token = crypto.randomBytes(32).toString("hex");
  const expires = new Date(Date.now() + 60 * 60 * 1000); // 1 hour

  await prisma.passwordReset.create({
    data: { userId: user.id, token, expires },
  });

  await sendEmail({
    to: email,
    subject: "Password Reset",
    html: `<a href="${process.env.NEXT_PUBLIC_APP_URL}/auth/reset?token=${token}">Reset Password</a>`,
  });

  return NextResponse.json({ message: "If account exists, email sent" });
}

// app/api/auth/reset-password/confirm/route.ts
export async function POST(req: Request) {
  const { token, password } = await req.json();

  const reset = await prisma.passwordReset.findUnique({ where: { token } });
  if (!reset || reset.used || reset.expires < new Date()) {
    return NextResponse.json({ error: "Invalid or expired token" }, { status: 400 });
  }

  const passwordHash = await bcrypt.hash(password, 12);
  await prisma.user.update({
    where: { id: reset.userId },
    data: { passwordHash },
  });

  await prisma.passwordReset.update({
    where: { id: reset.id },
    data: { used: true },
  });

  return NextResponse.json({ message: "Password updated" });
}
```

