## 2. Yjs Document Provider

```typescript
// lib/yjs-provider.ts
"use client";
import * as Y from "yjs";
import { WebsocketProvider } from "y-websocket";
import { useEffect, useState, useRef } from "react";

export function useYjsDoc(docId: string) {
  const docRef = useRef<Y.Doc | null>(null);
  const providerRef = useRef<WebsocketProvider | null>(null);
  const [connected, setConnected] = useState(false);
  const [awareness, setAwareness] = useState<any>(null);

  useEffect(() => {
    const doc = new Y.Doc();
    docRef.current = doc;

    const provider = new WebsocketProvider(
      process.env.NEXT_PUBLIC_WS_URL || "ws://localhost:1234",
      docId,
      doc
    );
    providerRef.current = provider;

    provider.on("sync", (isSynced: boolean) => {
      setConnected(isSynced);
    });

    setAwareness(provider.awareness);

    return () => {
      provider.disconnect();
      doc.destroy();
    };
  }, [docId]);

  return { doc: docRef.current, provider: providerRef.current, connected, awareness };
}

// Set user awareness
export function setAwarenessUser(awareness: any, user: { id: string; name: string; color: string }) {
  awareness.setLocalStateField("user", {
    name: user.name,
    color: user.color,
    colorLight: user.color + "40",
  });
}

// Get all connected users
export function getConnectedUsers(awareness: any) {
  const states = awareness.getStates();
  const users: Array<{ id: string; name: string; color: string; cursor?: any }> = [];
  states.forEach((state: any, clientId: number) => {
    if (state.user) {
      users.push({ id: String(clientId), ...state.user });
    }
  });
  return users;
}
```

## 3. Collaborative Editor Component

```tsx
// components/CollaborativeEditor.tsx
"use client";
import { useYjsDoc, setAwarenessUser } from "@/lib/yjs-provider";
import { useEffect, useRef, useState, useCallback } from "react";
import * as Y from "yjs";
import { QuillBinding } from "y-quill";
import Quill from "quill";
import "quill/dist/quill.snow.css";

const COLORS = ["#f44336", "#e91e63", "#9c27b0", "#3f51b5", "#2196f3", "#4caf50", "#ff9800"];

interface Props {
  docId: string;
  user: { id: string; name: string };
}

export function CollaborativeEditor({ docId, user }: Props) {
  const editorRef = useRef<HTMLDivElement>(null);
  const quillRef = useRef<Quill | null>(null);
  const bindingRef = useRef<QuillBinding | null>(null);
  const { doc, awareness, connected } = useYjsDoc(docId);
  const [users, setUsers] = useState<Array<{ id: string; name: string; color: string }>>([]);

  useEffect(() => {
    if (!editorRef.current || !doc || !awareness) return;

    // Initialize Quill
    const quill = new Quill(editorRef.current, {
      theme: "snow",
      placeholder: "Start typing...",
      modules: {
        toolbar: [
          [{ header: [1, 2, 3, false] }],
          ["bold", "italic", "underline", "strike"],
          [{ list: "ordered" }, { list: "bullet" }],
          ["link", "blockquote", "code-block"],
          ["clean"],
        ],
      },
    });
    quillRef.current = quill;

    // Bind Yjs to Quill
    const ytext = doc.getText("editor");
    const binding = new QuillBinding(ytext, quill, awareness);
    bindingRef.current = binding;

    // Set user awareness
    const color = COLORS[Math.floor(Math.random() * COLORS.length)];
    setAwarenessUser(awareness, { ...user, color });

    // Listen for awareness changes
    awareness.on("change", () => {
      const states = awareness.getStates();
      const connectedUsers: Array<{ id: string; name: string; color: string }> = [];
      states.forEach((state: any) => {
        if (state.user) connectedUsers.push(state.user);
      });
      setUsers(connectedUsers);
    });

    return () => {
      binding.destroy();
    };
  }, [doc, awareness, user]);

  return (
    <div className="flex flex-col h-full">
      {/* Presence bar */}
      <div className="flex items-center gap-2 p-2 border-b">
        <div className={`w-2 h-2 rounded-full ${connected ? "bg-green-500" : "bg-red-500"}`} />
        <span className="text-sm text-gray-600">
          {users.length} user{users.length !== 1 ? "s" : ""} connected
        </span>
        <div className="flex -space-x-1 ml-auto">
          {users.map((u) => (
            <div
              key={u.id}
              className="w-6 h-6 rounded-full border-2 border-white text-xs flex items-center justify-center text-white font-bold"
              style={{ backgroundColor: u.color }}
              title={u.name}
            >
              {u.name[0].toUpperCase()}
            </div>
          ))}
        </div>
      </div>

      {/* Editor */}
      <div ref={editorRef} className="flex-1 overflow-auto" />
    </div>
  );
}
