## 4. Live Cursors

```tsx
// components/LiveCursors.tsx
"use client";
import { useEffect, useState } from "react";

interface Cursor {
  userId: string;
  name: string;
  color: string;
  x: number;
  y: number;
}

export function LiveCursors({ awareness }: { awareness: any }) {
  const [cursors, setCursors] = useState<Cursor[]>([]);

  useEffect(() => {
    if (!awareness) return;

    const updateCursors = () => {
      const states = awareness.getStates();
      const newCursors: Cursor[] = [];
      states.forEach((state: any, clientId: number) => {
        if (state.user && state.cursor) {
          newCursors.push({
            userId: String(clientId),
            name: state.user.name,
            color: state.user.color,
            x: state.cursor.x,
            y: state.cursor.y,
          });
        }
      });
      setCursors(newCursors);
    };

    awareness.on("change", updateCursors);
    return () => awareness.off("change", updateCursors);
  }, [awareness]);

  return (
    <div className="pointer-events-none fixed inset-0 z-50">
      {cursors.map((cursor) => (
        <div
          key={cursor.userId}
          className="absolute transition-all duration-100 ease-out"
          style={{ left: cursor.x, top: cursor.y }}
        >
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
            <path d="M4 4L12 20L14 14L20 12L4 4Z" fill={cursor.color} stroke="white" strokeWidth="1" />
          </svg>
          <span
            className="absolute top-5 left-4 text-xs text-white px-1.5 py-0.5 rounded whitespace-nowrap"
            style={{ backgroundColor: cursor.color }}
          >
            {cursor.name}
          </span>
        </div>
      ))}
    </div>
  );
}
