## 2. Row-Level Security (PostgreSQL)

```sql
-- Enable RLS
ALTER TABLE "Tenant" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "User" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "Project" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "Task" ENABLE ROW LEVEL SECURITY;

-- Create tenant context function
CREATE OR REPLACE FUNCTION set_current_tenant(tenant_id TEXT)
RETURNS VOID AS $$
BEGIN
  PERFORM set_config('app.current_tenant', tenant_id, true);
END;
$$ LANGUAGE plpgsql;

-- Tenant isolation policies
CREATE POLICY tenant_isolation ON "Tenant"
  USING (id = current_setting('app.current_tenant')::TEXT);

CREATE POLICY user_tenant_isolation ON "User"
  USING ("tenantId" = current_setting('app.current_tenant')::TEXT);

CREATE POLICY project_tenant_isolation ON "Project"
  USING ("tenantId" = current_setting('app.current_tenant')::TEXT);

CREATE POLICY task_tenant_isolation ON "Task"
  USING (
    "projectId" IN (
      SELECT id FROM "Project"
      WHERE "tenantId" = current_setting('app.current_tenant')::TEXT
    )
  );

-- Index for RLS performance
CREATE INDEX idx_project_tenant ON "Project"("tenantId");
CREATE INDEX idx_task_project ON "Task"("projectId");
