## 4. Optimized Queries

```typescript
// lib/queries.ts
import { prisma } from "./prisma";
import { Prisma, TaskStatus, Priority } from "@prisma/client";

// Get projects with task counts
export async function getProjectsWithCounts(tenantId: string) {
  return prisma.project.findMany({
    where: { tenantId, status: "ACTIVE" },
    include: {
      _count: {
        select: {
          tasks: true,
          members: true,
        },
      },
      tasks: {
        select: { status: true },
      },
    },
    orderBy: { updatedAt: "desc" },
  });
}

// Get tasks with filtering and pagination
export async function getTasks(
  projectId: string,
  filters: {
    status?: TaskStatus;
    priority?: Priority;
    assigneeId?: string;
    search?: string;
    page?: number;
    limit?: number;
  }
) {
  const { status, priority, assigneeId, search, page = 1, limit = 50 } = filters;
  const skip = (page - 1) * limit;

  const where: Prisma.TaskWhereInput = {
    projectId,
    ...(status && { status }),
    ...(priority && { priority }),
    ...(assigneeId && { assigneeId }),
    ...(search && {
      OR: [
        { title: { contains: search, mode: "insensitive" } },
        { description: { contains: search, mode: "insensitive" } },
      ],
    }),
  };

  const [tasks, total] = await Promise.all([
    prisma.task.findMany({
      where,
      include: {
        assignee: { select: { id: true, name: true, avatar: true } },
      },
      orderBy: [{ priority: "desc" }, { position: "asc" }],
      skip,
      take: limit,
    }),
    prisma.task.count({ where }),
  ]);

  return { tasks, total, page, limit, pages: Math.ceil(total / limit) };
