import { Product } from "./product.model";
import { CreateProductInput, UpdateProductInput, ProductQuery } from "./product.types";
import { NotFoundError } from "@/shared/errors";
import { getOrSet, invalidatePattern } from "@/lib/cache";

export class ProductService {
  async create(data: CreateProductInput) {
    const product = await Product.create(data);
    await invalidatePattern("products:*");
    return product;
  }

  async getById(id: string) {
    return getOrSet(`products:${id}`, async () => {
      const product = await Product.findById(id);
      if (!product) throw new NotFoundError("Product not found");
      return product;
    });
  }

  async list(query: ProductQuery) {
    const { page, limit, sort, category, status, minPrice, maxPrice, search } = query;
    const filter: any = { status: status || "active" };

    if (category) filter.category = category;
    if (minPrice || maxPrice) {
      filter.price = {};
      if (minPrice) filter.price.$gte = minPrice;
      if (maxPrice) filter.price.$lte = maxPrice;
    }
    if (search) filter.$text = { $search: search };

    const [products, total] = await Promise.all([
      Product.find(filter)
        .sort(sort)
        .skip((page - 1) * limit)
        .limit(limit)
        .lean(),
      Product.countDocuments(filter),
    ]);

    return { products, total, page, limit, pages: Math.ceil(total / limit) };
  }

  async update(id: string, data: UpdateProductInput) {
    const product = await Product.findByIdAndUpdate(id, data, { new: true });
    if (!product) throw new NotFoundError("Product not found");
    await invalidatePattern(`products:${id}`);
    await invalidatePattern("products:*");
    return product;
  }

  async delete(id: string) {
    const product = await Product.findByIdAndDelete(id);
    if (!product) throw new NotFoundError("Product not found");
    await invalidatePattern(`products:${id}`);
    await invalidatePattern("products:*");
    return product;
  }

  async updateInventory(id: string, quantity: number) {
    const product = await Product.findByIdAndUpdate(
      id,
      { $inc: { inventory: quantity } },
      { new: true }
    );
    if (!product) throw new NotFoundError("Product not found");
    if (product.inventory < 0) throw new Error("Insufficient inventory");
    return product;
  }
}

