// src/modules/orders/order.service.ts
import { Order } from "./order.model";
import { Product } from "@/modules/products/product.model";
import { PaymentService } from "@/modules/payments/payment.service";
import { NotFoundError, BadRequestError } from "@/shared/errors";
import { createPaymentIntent } from "@/lib/stripe";

export class OrderService {
  private paymentService: PaymentService;

  constructor() {
    this.paymentService = new PaymentService();
  }

  async create(userId: string, items: Array<{ productId: string; quantity: number; variantSku?: string }>) {
    // Validate inventory and calculate total
    let total = 0;
    const orderItems = [];

    for (const item of items) {
      const product = await Product.findById(item.productId);
      if (!product) throw new NotFoundError(`Product ${item.productId} not found`);
      if (product.status !== "active") throw new BadRequestError(`Product ${product.name} is not available`);

      const variant = item.variantSku
        ? product.variants.find((v) => v.sku === item.variantSku)
        : null;

      const price = variant ? variant.price : product.price;
      const inventory = variant ? variant.inventory : product.inventory;

      if (inventory < item.quantity) {
        throw new BadRequestError(`Insufficient inventory for ${product.name}`);
      }

      total += price * item.quantity;
      orderItems.push({
        product: product._id,
        name: product.name,
        sku: variant ? variant.sku : product.sku,
        price,
        quantity: item.quantity,
        variant: variant ? { name: variant.name, attributes: variant.attributes } : undefined,
      });
    }

    // Create Stripe payment intent
    const paymentIntent = await createPaymentIntent(total, "usd", {
      userId,
      itemCount: items.length,
    });

    // Create order
    const order = await Order.create({
      userId,
      items: orderItems,
      total,
      status: "pending",
      paymentIntentId: paymentIntent.id,
    });

    // Decrement inventory
    for (const item of items) {
      if (item.variantSku) {
        await Product.findByIdAndUpdate(item.productId, {
          $inc: { "variants.$[v].inventory": -item.quantity },
        }, {
          arrayFilters: [{ "v.sku": item.variantSku }],
        });
      } else {
        await Product.findByIdAndUpdate(item.productId, {
          $inc: { inventory: -item.quantity },
        });
      }
    }

    return { order, clientSecret: paymentIntent.client_secret };
  }

  async confirmPayment(orderId: string, paymentIntentId: string) {
    const order = await Order.findById(orderId);
    if (!order) throw new NotFoundError("Order not found");
    if (order.paymentIntentId !== paymentIntentId) throw new BadRequestError("Payment mismatch");

    order.status = "confirmed";
    order.paidAt = new Date();
    await order.save();

    return order;
  }

  async getUserOrders(userId: string, page = 1, limit = 20) {
    const [orders, total] = await Promise.all([
      Order.find({ userId })
        .sort({ createdAt: -1 })
        .skip((page - 1) * limit)
        .limit(limit)
        .lean(),
      Order.countDocuments({ userId }),
    ]);
    return { orders, total, page, limit, pages: Math.ceil(total / limit) };
  }
}
