// store/kanban-store.ts
import { create } from "zustand";
import { immer } from "zustand/middleware/immer";
import { devtools } from "zustand/middleware";

export interface Task {
  id: string;
  title: string;
  description?: string;
  priority: "low" | "medium" | "high" | "urgent";
  assignee?: { id: string; name: string; avatar: string };
  labels: string[];
  dueDate?: string;
  createdAt: string;
  updatedAt: string;
}

export interface Column {
  id: string;
  title: string;
  taskIds: string[];
  color: string;
}

export interface Board {
  id: string;
  title: string;
  columns: Column[];
  tasks: Record<string, Task>;
}

interface KanbanState {
  board: Board | null;
  isLoading: boolean;
  error: string | null;
  selectedTask: string | null;
  draggedTask: string | null;

  // Actions
  setBoard: (board: Board) => void;
  moveTask: (taskId: string, fromColumnId: string, toColumnId: string, newIndex: number) => void;
  reorderTasks: (columnId: string, oldIndex: number, newIndex: number) => void;
  addTask: (columnId: string, task: Task) => void;
  updateTask: (taskId: string, updates: Partial<Task>) => void;
  removeTask: (columnId: string, taskId: string) => void;
  setSelectedTask: (taskId: string | null) => void;
  setDraggedTask: (taskId: string | null) => void;
  optimisticMove: (taskId: string, fromColumnId: string, toColumnId: string, newIndex: number) => void;
  revertMove: (previousState: Board) => void;
}

export const useKanbanStore = create<KanbanState>()(
  devtools(
    immer((set, get) => ({
      board: null,
      isLoading: false,
      error: null,
      selectedTask: null,
      draggedTask: null,

      setBoard: (board) => set({ board, isLoading: false }),

      moveTask: (taskId, fromColumnId, toColumnId, newIndex) =>
        set((state) => {
          if (!state.board) return;
          const fromColumn = state.board.columns.find((c) => c.id === fromColumnId);
          const toColumn = state.board.columns.find((c) => c.id === toColumnId);
          if (!fromColumn || !toColumn) return;

          const taskIndex = fromColumn.taskIds.indexOf(taskId);
          if (taskIndex === -1) return;

          fromColumn.taskIds.splice(taskIndex, 1);
          toColumn.taskIds.splice(newIndex, 0, taskId);
        }),

      reorderTasks: (columnId, oldIndex, newIndex) =>
        set((state) => {
          if (!state.board) return;
          const column = state.board.columns.find((c) => c.id === columnId);
          if (!column) return;

          const [moved] = column.taskIds.splice(oldIndex, 1);
          column.taskIds.splice(newIndex, 0, moved);
        }),

      addTask: (columnId, task) =>
        set((state) => {
          if (!state.board) return;
          state.board.tasks[task.id] = task;
          const column = state.board.columns.find((c) => c.id === columnId);
          if (column) column.taskIds.push(task.id);
        }),

      updateTask: (taskId, updates) =>
        set((state) => {
          if (!state.board) return;
          const task = state.board.tasks[taskId];
          if (task) Object.assign(task, updates);
        }),

      removeTask: (columnId, taskId) =>
        set((state) => {
          if (!state.board) return;
          const column = state.board.columns.find((c) => c.id === columnId);
          if (column) {
            column.taskIds = column.taskIds.filter((id) => id !== taskId);
          }
          delete state.board.tasks[taskId];
        }),

      setSelectedTask: (taskId) => set({ selectedTask: taskId }),
      setDraggedTask: (taskId) => set({ draggedTask: taskId }),

      optimisticMove: (taskId, fromColumnId, toColumnId, newIndex) => {
        const previousState = JSON.parse(JSON.stringify(get().board));
        get().moveTask(taskId, fromColumnId, toColumnId, newIndex);
        return previousState;
      },

      revertMove: (previousState) => set({ board: previousState }),
    })),
    { name: "kanban-store" }
  )
);
