export function useMoveTask() {
  const queryClient = useQueryClient();
  const optimisticMove = useKanbanStore((s) => s.optimisticMove);
  const revertMove = useKanbanStore((s) => s.revertMove);

  return useMutation({
    mutationFn: async ({
      taskId,
      fromColumnId,
      toColumnId,
      newIndex,
    }: {
      taskId: string;
      fromColumnId: string;
      toColumnId: string;
      newIndex: number;
    }) => {
      await api.patch(`/tasks/${taskId}/move`, {
        fromColumnId,
        toColumnId,
        newIndex,
      });
    },
    onMutate: async ({ taskId, fromColumnId, toColumnId, newIndex }) => {
      await queryClient.cancelQueries({ queryKey: ["board"] });
      const previousState = optimisticMove(taskId, fromColumnId, toColumnId, newIndex);
      return { previousState };
    },
    onError: (err, variables, context) => {
      if (context?.previousState) {
        revertMove(context.previousState);
      }
    },
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: ["board"] });
    },
  });
}

