      const { data } = await api.post("/tasks", { columnId, title, description });
      return data;
    },
    onSuccess: (data, { columnId }) => {
      addTask(columnId, data);
    },
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: ["board"] });
    },
  });
