    useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  );

  function handleDragStart(event: DragStartEvent) {
    setActiveId(event.active.id as string);
    setDraggedTask(event.active.id as string);
  }

  function handleDragOver(event: DragOverEvent) {
    const { active, over } = event;
    if (!over || !board) return;

    const activeId = active.id as string;
    const overId = over.id as string;

    // Find which columns the items are in
    const activeColumn = board.columns.find((c) => c.taskIds.includes(activeId));
    const overColumn = board.columns.find(
      (c) => c.id === overId || c.taskIds.includes(overId)
    );

    if (!activeColumn || !overColumn || activeColumn.id === overColumn.id) return;

    // Move task to new column
    const overIndex = overColumn.taskIds.indexOf(overId);
    useKanbanStore.getState().moveTask(
      activeId,
      activeColumn.id,
      overColumn.id,
      overIndex >= 0 ? overIndex : overColumn.taskIds.length
    );
  }

  function handleDragEnd(event: DragEndEvent) {
    const { active, over } = event;
    setActiveId(null);
    setDraggedTask(null);

    if (!over || !board) return;

    const activeId = active.id as string;
    const overId = over.id as string;

    const activeColumn = board.columns.find((c) => c.taskIds.includes(activeId));
    const overColumn = board.columns.find(
      (c) => c.id === overId || c.taskIds.includes(overId)
    );

    if (!activeColumn || !overColumn) return;

    if (activeColumn.id === overColumn.id) {
      // Reorder within same column
      const oldIndex = activeColumn.taskIds.indexOf(activeId);
      const newIndex = overColumn.taskIds.indexOf(overId);
      if (oldIndex !== newIndex) {
        moveTask.mutate({
          taskId: activeId,
          fromColumnId: activeColumn.id,
          toColumnId: overColumn.id,
          newIndex,
        });
      }
    } else {
      // Move to different column
      const newIndex = overColumn.taskIds.indexOf(overId);
      moveTask.mutate({
        taskId: activeId,
        fromColumnId: activeColumn.id,
        toColumnId: overColumn.id,
        newIndex: newIndex >= 0 ? newIndex : overColumn.taskIds.length,
      });
    }
  }

  if (!board) return <div>Loading...</div>;

  const activeTask = activeId ? board.tasks[activeId] : null;

  return (
    <DndContext
      sensors={sensors}
      collisionDetection={closestCorners}
      onDragStart={handleDragStart}
      onDragOver={handleDragOver}
      onDragEnd={handleDragEnd}
    >
      <div className="flex gap-4 overflow-x-auto p-4 h-full">
        {board.columns.map((column) => (
          <KanbanColumn key={column.id} column={column} />
        ))}
      </div>

      <DragOverlay>
        {activeTask ? <KanbanCard task={activeTask} isDragOverlay /> : null}
      </DragOverlay>
    </DndContext>
  );
}

