## 3. Subscription Management API

```typescript
// app/api/subscription/route.ts
import { NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { createCheckoutSession, createPortalSession, stripe } from "@/lib/stripe";

export async function GET() {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const user = await prisma.user.findUnique({ where: { id: session.user.id } });
  if (!user?.stripeSubscriptionId) {
    return NextResponse.json({ subscription: null });
  }

  const subscription = await stripe.subscriptions.retrieve(user.stripeSubscriptionId, {
    expand: ["latest_invoice", "default_payment_method"],
  });

  return NextResponse.json({
    subscription: {
      id: subscription.id,
      status: subscription.status,
      currentPeriodEnd: new Date(subscription.current_period_end * 1000),
      cancelAtPeriodEnd: subscription.cancel_at_period_end,
      trialEnd: subscription.trial_end ? new Date(subscription.trial_end * 1000) : null,
      plan: subscription.items.data[0]?.price,
    },
  });
}

export async function POST(req: Request) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { action, priceId } = await req.json();

  if (action === "checkout") {
    const checkoutSession = await createCheckoutSession({
      userId: session.user.id,
      priceId,
      successUrl: `${process.env.NEXT_PUBLIC_APP_URL}/settings/billing?success=true`,
      cancelUrl: `${process.env.NEXT_PUBLIC_APP_URL}/settings/billing?cancelled=true`,
    });
    return NextResponse.json({ url: checkoutSession.url });
  }

  if (action === "portal") {
    const user = await prisma.user.findUnique({ where: { id: session.user.id } });
    if (!user?.stripeCustomerId) {
      return NextResponse.json({ error: "No subscription found" }, { status: 400 });
    }
    const portalSession = await createPortalSession(
      user.stripeCustomerId,
      `${process.env.NEXT_PUBLIC_APP_URL}/settings/billing`
    );
    return NextResponse.json({ url: portalSession.url });
  }

  if (action === "cancel") {
    const user = await prisma.user.findUnique({ where: { id: session.user.id } });
    if (!user?.stripeSubscriptionId) {
      return NextResponse.json({ error: "No subscription found" }, { status: 400 });
    }
    await stripe.subscriptions.update(user.stripeSubscriptionId, {
      cancel_at_period_end: true,
    });
    return NextResponse.json({ message: "Subscription will cancel at period end" });
  }

  return NextResponse.json({ error: "Invalid action" }, { status: 400 });
}
